	 * Specifies that any lowercase characters in the current text run are formatted for display only as their capital letter character equivalents.
	 *
	 * ## Try it
	 * 
	 * ```js document-builder
	 * builder.CreateFile("pptx");
	 * var oPresentation = Api.GetPresentation();
	 * var oSlide = oPresentation.GetSlideByIndex(0);
	 * oSlide.RemoveAllObjects();
	 * var oFill = Api.CreateSolidFill(Api.CreateRGBColor(255, 111, 61));
	 * var oStroke = Api.CreateStroke(0, Api.CreateNoFill());
	 * var oShape = Api.CreateShape("flowChartMagneticTape", 300 * 36000, 130 * 36000, oFill, oStroke);
	 * oShape.SetPosition(608400, 1267200);
	 * var oDocContent = oShape.GetDocContent();
	 * var oParagraph = oDocContent.GetElement(0);
	 * var oRun = Api.CreateRun();
	 * oRun.AddText("This is just a sample text. ");
	 * oParagraph.AddElement(oRun);
	 * oRun = Api.CreateRun();
	 * oRun.SetCaps(true);
	 * oRun.AddText("This is a text run with the font set to capitalized letters.");
	 * oParagraph.AddElement(oRun);
	 * oSlide.AddObject(oShape);
	 * builder.SaveFile("pptx", "SetCaps.pptx");
	 * builder.CloseFile();
	 * 
	 * ```
	 *
	 * @memberof ApiRun
	 * @param {boolean} isCaps - Specifies that the contents of the current run are displayed capitalized.
	 * @returns {ApiTextPr}
	 * @see office-js-api/Examples/Word/ApiRun/Methods/SetCaps.js
	 */

description:
Specifies that any lowercase characters in the current text run are formatted for display only as their capital letter character equivalents.

## Try it

```js document-builder
builder.CreateFile("pptx");
var oPresentation = Api.GetPresentation();
var oSlide = oPresentation.GetSlideByIndex(0);
oSlide.RemoveAllObjects();
var oFill = Api.CreateSolidFill(Api.CreateRGBColor(255, 111, 61));
var oStroke = Api.CreateStroke(0, Api.CreateNoFill());
var oShape = Api.CreateShape("flowChartMagneticTape", 300 * 36000, 130 * 36000, oFill, oStroke);
